--
-- Table structure for table `guide_jobs`
--

DROP TABLE IF EXISTS `guide_jobs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `guide_jobs` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `status` varchar(10) NOT NULL DEFAULT 'QUEUED' COMMENT 'QUEUED: QUEUED\nPROCESSING: PROCESSING\nSUCCEEDED: SUCCEEDED\nFAILED: FAILED',
  `retry_count` int NOT NULL DEFAULT '0',
  `max_retries` int NOT NULL DEFAULT '3',
  `failure_code` varchar(24) DEFAULT NULL COMMENT 'OCR_NOT_READY: OCR_NOT_READY\nOCR_RESULT_NOT_FOUND: OCR_RESULT_NOT_FOUND\nINVALID_STATE_TRANSITION: INVALID_STATE_TRANSITION\nPROCESSING_ERROR: PROCESSING_ERROR',
  `error_message` longtext,
  `queued_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `started_at` datetime(6) DEFAULT NULL,
  `completed_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  `user_id` bigint NOT NULL,
  `ocr_job_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_guide_jobs_user_id_status` (`user_id`,`status`),
  KEY `idx_guide_jobs_ocr_job_id_created_at` (`ocr_job_id`,`created_at`),
  KEY `idx_guide_jobs_status_retry_count` (`status`,`retry_count`),
  CONSTRAINT `fk_guide_jobs_ocr_jobs` FOREIGN KEY (`ocr_job_id`) REFERENCES `ocr_jobs` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_guide_jobs_users` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=70 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `guide_jobs`
--

LOCK TABLES `guide_jobs` WRITE;
/*!40000 ALTER TABLE `guide_jobs` DISABLE KEYS */;
