INSERT INTO `notifications` VALUES (1,'HEALTH_ALERT','수면 안전 알림','수면이 부족하거나 자주 깨어나는 경우, 주의력이나 판단력이 저하될 수 있습니다. 만약 지나치게 졸리거나 피곤함을 느낀다면 운전이나 위험한 활동을 피하는 것이 좋습니다. 충분한 휴식과 회복을 우선시하고, 수면 문제가 지속된다면 의료 전문가와 상담하시기 바랍니다.',1,'2026-03-07 16:49:06.204310','{\"event\": \"health_alert\", \"severity\": \"HIGH\", \"alert_key\": \"SLEEP::CONDITION_1\", \"alert_type\": \"SLEEP\"}','2026-03-06 18:23:44.823743',3),(2,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-07 16:49:06.204310','{\"event\": \"guide_ready\", \"ocr_job_id\": 27, \"risk_level\": \"MEDIUM\", \"guide_job_id\": 13}','2026-03-06 18:23:54.256203',3),(3,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-07 16:49:06.204310','{\"event\": \"guide_ready\", \"ocr_job_id\": 27, \"risk_level\": \"MEDIUM\", \"guide_job_id\": 14}','2026-03-06 18:24:13.802711',3),(4,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event\": \"guide_ready\", \"ocr_job_id\": 32, \"risk_level\": \"MEDIUM\", \"guide_job_id\": 15}','2026-03-07 23:34:24.745572',3),(5,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event\": \"guide_ready\", \"ocr_job_id\": 32, \"risk_level\": \"MEDIUM\", \"guide_job_id\": 16}','2026-03-07 23:34:44.468700',3),(6,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event\": \"guide_ready\", \"ocr_job_id\": 33, \"risk_level\": \"LOW\", \"guide_job_id\": 17}','2026-03-07 23:42:36.360171',3),(7,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event\": \"guide_ready\", \"ocr_job_id\": 33, \"risk_level\": \"LOW\", \"guide_job_id\": 18}','2026-03-07 23:42:55.102065',3),(8,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event\": \"guide_ready\", \"ocr_job_id\": 34, \"risk_level\": \"LOW\", \"guide_job_id\": 19}','2026-03-08 15:13:38.454948',3),(9,'GUIDE_READY','가이드 생성 완료','요청하신 건강 가이드가 생성되었습니다.',1,'2026-03-11 10:07:48.185500','{\"event